import java.util.ArrayList;import java.util.Arrays;import java.util.List;import java.util.Map;
final class TemplateMethodPattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}
abstract static class Job{abstract String format();abstract List<String>transform(String payload);Map<String,Object>run(String payload){if(payload.isEmpty())throw new PatternException("invalid_payload");return Map.of("format",format(),"data",transform(payload),"steps",List.of("validate","transform:"+format(),"persist"));}}static final class CsvJob extends Job{String format(){return"csv";}List<String>transform(String p){return Arrays.asList(p.split(",",-1));}}static final class JsonJob extends Job{String format(){return"json";}List<String>transform(String p){return Arrays.asList(p.split("\\|",-1));}}
@SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){List<Map<String,Object>>out=new ArrayList<>();for(Map<String,Object>value:(List<Map<String,Object>>)input.getOrDefault("jobs",List.of())){Job job=switch(String.valueOf(value.get("format"))){case"csv"->new CsvJob();case"json"->new JsonJob();default->throw new PatternException("unsupported_format");};out.add(job.run(String.valueOf(value.getOrDefault("payload",""))));}return Map.of("results",out);}}
